import json
import logging
import os
import socket
import urllib.parse
import urllib.request

logger = logging.getLogger()
logger.setLevel(logging.INFO)

MAX_URLS = int(os.environ.get("MAX_ENRICH_URLS", "5"))
MAX_RESPONSE_BYTES = int(os.environ.get("MAX_ENRICH_RESPONSE_BYTES", "65536"))
REQUEST_TIMEOUT_SECONDS = float(os.environ.get("ENRICH_TIMEOUT_SECONDS", "2.0"))
ALLOWED_SCHEMES = {"https"}
ALLOWED_HOSTS = {
    host.strip().lower()
    for host in os.environ.get("ALLOWED_ENRICH_HOSTS", "").split(",")
    if host.strip()
}
BLOCK_PRIVATE_IPS = os.environ.get("BLOCK_PRIVATE_IPS", "true").lower() != "false"


def _cf_headers_to_dict(headers):
    result = {}
    for key, values in (headers or {}).items():
        if values:
            result[key.lower()] = [v.get("value", "") for v in values]
    return result


def _add_header(headers, name, value):
    key = name.lower()
    headers[key] = [{"key": name, "value": value}]


def _get_header_values(headers, name):
    values = headers.get(name.lower(), [])
    return [v.get("value", "") for v in values if "value" in v]


def _is_private_ip(ip):
    try:
        infos = socket.getaddrinfo(ip, None)
        for info in infos:
            sockaddr = info[4]
            addr = sockaddr[0]
            parsed = None
            try:
                import ipaddress
                parsed = ipaddress.ip_address(addr)
            except Exception:
                continue
            if (
                parsed.is_private
                or parsed.is_loopback
                or parsed.is_link_local
                or parsed.is_multicast
                or parsed.is_reserved
                or parsed.is_unspecified
            ):
                return True
        return False
    except Exception:
        return True


def _validate_url(raw_url):
    if not raw_url or len(raw_url) > 2048:
        raise ValueError("invalid_url_length")

    parsed = urllib.parse.urlparse(raw_url)
    if parsed.scheme.lower() not in ALLOWED_SCHEMES:
        raise ValueError("scheme_not_allowed")
    if not parsed.hostname:
        raise ValueError("missing_hostname")
    if parsed.username or parsed.password:
        raise ValueError("userinfo_not_allowed")
    if parsed.fragment:
        raise ValueError("fragment_not_allowed")

    hostname = parsed.hostname.lower()

    if ALLOWED_HOSTS and hostname not in ALLOWED_HOSTS:
        raise ValueError("host_not_allowed")

    if BLOCK_PRIVATE_IPS:
        try:
            infos = socket.getaddrinfo(hostname, parsed.port or 443, type=socket.SOCK_STREAM)
            for info in infos:
                addr = info[4][0]
                if _is_private_ip(addr):
                    raise ValueError("private_ip_not_allowed")
        except ValueError:
            raise
        except Exception:
            raise ValueError("dns_resolution_failed")

    return parsed.geturl()


def _fetch_url(url):
    req = urllib.request.Request(
        url,
        headers={
            "User-Agent": "lambda-edge-enrichment/1.0",
            "Accept": "application/json,text/plain,*/*",
        },
        method="GET",
    )
    with urllib.request.urlopen(req, timeout=REQUEST_TIMEOUT_SECONDS) as resp:
        status = getattr(resp, "status", None) or resp.getcode()
        body = resp.read(MAX_RESPONSE_BYTES + 1)
        if len(body) > MAX_RESPONSE_BYTES:
            raise ValueError("response_too_large")
        content_type = resp.headers.get("Content-Type", "")
        return {
            "url": url,
            "status": int(status),
            "content_type": content_type,
            "body": body.decode("utf-8", errors="replace"),
        }


def lambda_handler(event, context):
    record = event["Records"][0]["cf"]
    request = record["request"]
    headers = request.get("headers", {})

    enrich_urls = _get_header_values(headers, "x-enrich-url")
    enrich_urls = [u.strip() for u in enrich_urls if u and u.strip()][:MAX_URLS]

    results = []
    errors = []

    for raw_url in enrich_urls:
        try:
            safe_url = _validate_url(raw_url)
            result = _fetch_url(safe_url)
            results.append(result)
        except Exception as e:
            logger.warning("Enrichment fetch failed for %s: %s", raw_url, str(e))
            errors.append({"url": raw_url, "error": str(e)})

    if results:
        payload = json.dumps(results, separators=(",", ":"))
        _add_header(headers, "X-Enrich-Context", payload)

    if errors:
        payload = json.dumps(errors, separators=(",", ":"))
        _add_header(headers, "X-Enrich-Errors", payload)

    request["headers"] = headers
    return request